command:
const MODULE_ID = "substances-and-paraphernalia";
const FLAG_SOURCE = "sourceSubstanceId";
if (!game.user.isGM) { ui.notifications.warn("GM only."); return; }
const actor = canvas.tokens.controlled[0]?.actor ?? game.user.character;
if (!actor) { ui.notifications.warn(game.i18n.localize("FISHUT.RemoveAddiction.NoActor")); return; }
const rows = [];
for (const effect of actor.effects) {
  const sid = effect.flags?.[MODULE_ID]?.[FLAG_SOURCE] ?? null;
  const stacks = Number(effect.flags?.[MODULE_ID]?.stacks) || null;
  const nameMatch = /tolerance/i.test(effect.name ?? "");
  if ((sid && stacks) || nameMatch) {
    rows.push({ effect, sourceId: sid, stacks: stacks ?? 1 });
  }
}
if (rows.length === 0) { ui.notifications.info(game.i18n.format("FISHUT.RemoveTolerance.NoCandidates", { actor: actor.name })); return; }
const body = `${game.i18n.format("FISHUT.RemoveTolerance.PreviewIntro", { actor: actor.name })}<ul style="list-style:none;padding-left:0;">${rows.map((r, i) => `<li><label><input type="checkbox" name="row-${i}" checked> ${game.i18n.format("FISHUT.RemoveTolerance.RowDetail", { name: r.effect?.name ?? "(unknown)", sourceId: r.sourceId ?? "(none)", stacks: r.stacks })}</label></li>`).join("")}</ul>`;
const result = await foundry.applications.api.DialogV2.wait({
  window: { title: game.i18n.localize("FISHUT.RemoveTolerance.Title") },
  content: body,
  buttons: [
    { action: "confirm", label: game.i18n.localize("FISHUT.RemoveAddiction.Confirm"), default: true,
      callback: (event, button) => { const fd = new FormData(button.form); return rows.map((_, i) => fd.has(`row-${i}`)); } },
    { action: "cancel", label: game.i18n.localize("FISHUT.RemoveAddiction.Cancel"), default: false,
      callback: () => null }
  ],
  rejectClose: false, modal: true,
});
if (!Array.isArray(result)) return;
const removeIds = [];
let removed = 0;
const log = [];
for (let i = 0; i < rows.length; i++) {
  if (!result[i]) continue;
  const row = rows[i];
  if (row.effect) {
    log.push(row.effect.toObject());
    removeIds.push(row.effect.id);
  }
  removed++;
}
if (removeIds.length) await actor.deleteEmbeddedDocuments("ActiveEffect", removeIds, { fishutIntentional: true });
if (log.length) {
  await ChatMessage.create({
    user: game.user.id,
    whisper: ChatMessage.getWhisperRecipients("GM").map((u) => u.id),
    content: `<details><summary>${game.i18n.localize("FISHUT.RemoveTolerance.LogTitle")}</summary><pre>${foundry.utils.escapeHTML(JSON.stringify(log, null, 2))}</pre></details>`,
  });
}
ui.notifications.info(game.i18n.format("FISHUT.RemoveTolerance.Removed", { actor: actor.name, count: removed }));
